import java.util.stream.IntStream;

public class Main {
    public static void main(String[] args) {
        // Define the given value
        int givenValue = 5;

        // Use Java streams to print integers greater than the given value
        IntStream.range(1, 100) // Generate a stream of integers from 1 to 99
                .filter(i -> i > givenValue) // Filter integers greater than the given value
                .forEach(System.out::println); // Print the filtered integers
    }
}
```

