To create a proxy in an ASP.NET Core API, you can use the `HttpClient` class to make requests to the target endpoint. Here's an example of how you can do this:

**1. Create a new controller**

In your ASP.NET Core API project, create a new controller that will handle the proxy requests. For example, let's create a `ProxyController.cs` file:
```csharp
using Microsoft.AspNetCore.Mvc;
using System.Net.Http;
using System.Threading.Tasks;

namespace MyApi.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class ProxyController : ControllerBase
    {
        private readonly HttpClient _httpClient;

        public ProxyController(IHttpClientFactory httpClientFactory)
        {
            _httpClient = httpClientFactory.CreateClient();
        }

        [HttpGet("{path}")]
        public async Task<IActionResult> GetAsync([FromRoute] string path)
        {
            var request = new HttpRequestMessage(HttpMethod.Get, path);
            var response = await _httpClient.SendAsync(request);

            if (response.IsSuccessStatusCode)
            {
                return new OkObjectResult(await response.Content.ReadAsStringAsync());
            }
            else
            {
                return new StatusCodeResult((int)response.StatusCode);
            }
        }
    }
}
```
